class Solution(object):
    def firstMissingPositive(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        if not nums:
            return 1

        n = len(nums)

        # Use negative numbers and zero as placeholders for the missing numbers
        for i in range(n):
            if nums[i] <= 0 or nums[i] > n:
                nums[i] = 1

        # Use indices as placeholders for the numbers
        for i in range(n):
            a = abs(nums[i])

            # If the number at index a is positive, mark it as negative to indicate that it is present
            if nums[a] > 0:
                nums[a] = -abs(nums[a])

        # The first missing positive is the first positive number
        for i in range(1, n):
            if nums[i] > 0:
                return i

        # If all numbers from 1 to n are present, return n+1
        if nums[0] > 0:
            return n + 1

        # If no positive missing number is found, return n+1
        return n + 1

