        nums = [str(i) for i in range(1, n+1)]
        fact = [1]
        for i in range(1, n+1):
            fact.append(fact[-1]*i)
        k -= 1  # adjust for 1-indexing
        res = []
        for i in range(n, 0, -1):
            index = k // fact[i-1]
