import heapq

class Solution(object):
    def smallestDistancePair(self, nums, k):
        """
        :type nums: List[int]
        :type k: int
        :rtype: int
        """
        nums.sort()
        min_heap = []
        for i in range(len(nums)-1):
            diff = nums[i+1] - nums[i]
            heapq.heappush(min_heap, diff)
            if len(min_heap) > k:
                heapq.heappop(min_heap)
        return sum(min_heap)

