class Solution(object):
    def searchRange(self, nums, target):
        """
        :type nums: List[int]
        :type target: int
        :rtype: List[int]
        """
        def binary_search(nums, target, left):
            left_index = 0
            right_index = len(nums) - 1
            while left_index <= right_index:
                mid_index = (left_index + right_index) // 2
                if nums[mid_index] > target or (left and mid_index == right_index):
                    right_index = mid_index - 1
                else:
                    left_index = mid_index + 1
            return left_index if left else -1

        def find_range(nums, target):
            left_index = binary_search(nums, target, True)
            right_index = binary_search(nums, target, False) - 1
            if left_index <= right_index:
                return [left_index, right_index]
            else:
                return [-1, -1]

        return find_range(nums, target)

