class Solution(object):
    def toHex(self, num):
        """
        :type num: int
        :rtype: str
        """
        if num == 0:
            return '0'

        # create a dictionary for hexadecimal digits
        hex_map = {10: 'a', 11: 'b', 12: 'c', 13: 'd', 14: 'e', 15: 'f'}

        # convert to two's complement if num is negative
        if num < 0:
            num = (1 << 32) + num

        result = ''
        while num > 0:
            remainder = num % 16
            num = num // 16

            # add the hexadecimal digit to the result
            if remainder > 9:
                result = hex_map[remainder] + result
            else:
                result = str(remainder) + result

        return result

