class Solution(object):
    def maximumGap(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        if len(nums) < 2:
            return 0

        min_num = min(nums)
        max_num = max(nums)
        bucket_size = (max_num - min_num) / (len(nums) - 1)
        bucket_count = ((max_num - min_num) / bucket_size) + 1

        min_bucket = [None] * bucket_count
        max_bucket = [None] * bucket_count

        for num in nums:
            if num == min_num:
                min_bucket[0] = num
            else:
                bucket_index = (num - min_num) / bucket_size
                if min_bucket[bucket_index] is None:
                    min_bucket[bucket_index] = num
                else:
                    min_bucket[bucket_index] = min(min_bucket[bucket_index], num)

        for num in nums[::-1]:
            if num == max_num:
                max_bucket[0] = num
            else:
                bucket_index = (num - min_num) / bucket_size
                if max_bucket[bucket_index] is None:
                    max_bucket[bucket_index] = num
                else:
                    max_bucket[bucket_index] = max(max_bucket[bucket_index], num)

        max_gap = 0
        for i in range(bucket_count - 1):
            if min_bucket[i] is not None and max_bucket[i] is not None:
                gap = (max_bucket[i] - min_bucket[i])
                max_gap = max(max_gap, gap)

        return max_gap

