class Solution(object):
    def minSwapsCouples(self, row):
        """
        :type row: List[int]
        :rtype: int
        """
        n = len(row) // 2
        parent = {}
        for i in range(n):
            x = row[2*i]
            y = row[2*i+1]
            parent[x] = x
            parent[y] = x

        for i in range(n):
            x = self.find(row[2*i], parent)
            y = self.find(row[2*i+1], parent)
            if x != y:
                self.union(row[2*i], row[2*i+1], parent)
                i -= 1
        return n - sum(self.find(x, parent) == x for x in parent)

    def find(self, x, parent):
        if parent[x] != x:
            parent[x] = self.find(parent[x], parent)
        return parent[x]

    def union(self, x, y, parent):
        x_par = self.find(x, parent)
        y_par = self.find(y, parent)
        parent[x_par] = y_par

