    def isInterleave(self, s1, s2, s3):
        """
        :type s1: str
        :type s2: str
        :type s3: str
        :rtype: bool
        """
        len1 = len(s1)
        len2 = len(s2)
        len3 = len(s3)

        # check if s3 can be formed by interleaving s1 and s2
        if len1 + len2 != len3:
            return False

        # dp[i][j] is True if s3[:i+j] can be formed by s1[:i] and s2[:j]
        dp = [[False]*(len2+1) for _ in range(len1+1)]

        # init
        dp[0][0] = True
        for i in range(1, len1+1):
            if s1[i-1] == s3[i-1] and s1[i-1] == s2[0]:
                dp[i][0] = dp[i-1][0]
        for j in range(1, len2+1):
            if s2[j-1] == s3[j-1] and s2[j-1] == s1[0]:
                dp[0][j] = dp[0][j-1]

        # dp transition
        for i in range(1, len1+1):
            for j in range(1, len2+1):
                if s1[i-1] == s3[i+j-1] and s1[i-1] == s2[j-1]:
                    dp[i][j] = dp[i-1][j-1] or dp[i][j]
                if s2[j-1] == s3[i+j-1] and s2[j-1] == s1[i-1]:
                    dp[i][j] = dp[i][j-1] or dp[i][j]

