def cutOffTree(forest):
    m, n, ans = len(forest), len(forest[0]), 0
    trees = [(0, 0, 0)]
    for i in range(m):
        for j in range(n):
            if forest[i][j] > 1:
                heappush(trees, (forest[i][j], i, j))
    while len(trees) > 1:
        height, x, y = heappop(trees)
        while True:
            nx, ny, nh = x, y, 0
            if len(trees) == 0 or trees[0][0] > height:
                return -1
            while x == trees[0][1] and y == trees[0][2]:
                nx, ny, nh = heappop(trees)[1:]
            dx, dy = (nx - x, ny - y)
            if dx == 0:
                d = abs(dy)
            elif dy == 0:
                d = abs(dx)
            else:
                d = abs(dx) / abs(dy)
            ans += d
            x, y, height = nx, ny, nh
            if (x, y) == (trees[0][1], trees[0][2]):
                heappop(trees)
            if len(trees) == 0:
