    def findLUSlength(self, a, b):
        """
        :type a: str
        :type b: str
        :rtype: int
        """
        def is_subsequence(a, b):
            i, j = 0, 0
            while i < len(a) and j < len(b):
                if a[i] == b[j]:
                    j += 1
                i += 1
            return j == len(b)

        return max(map(len, [a, b])) if not is_subsequence(a, b) and not is_subsequence(b, a) else -1

