import heapq

class Solution(object):
    def trapRainWater(self, heightMap):
        """
        :type heightMap: List[List[int]]
        :rtype: int
        """
        if not heightMap or not heightMap[0]:
            return 0

        m, n = len(heightMap), len(heightMap[0])
        heap = []
        visited = [[0]*n for _ in range(m)]
        total_water = 0

        # Put all boundary cells into the heap
        for i in range(m):
            for j in range(n):
                if i == 0 or i == m-1 or j == 0 or j == n-1:
                    heapq.heappush(heap, (heightMap[i][j], (i, j)))
                    visited[i][j] = 1

        # While there are still cells in the heap
        while heap:
            height, (i, j) = heapq.heappop(heap)
            for di, dj in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
                ni, nj = i + di, j + dj
                if 0 <= ni < m and 0 <= nj < n and not visited[ni][nj] and heightMap[ni][nj] < height:
                    total_water += height - heightMap[ni][nj]
                    heapq.heappush(heap, (heightMap[ni][nj], (ni, nj)))
                    visited[ni][nj] = 1

        return total_water

