            for j in range(len(board[0])):
                if board[i][j] == 'O':
                    board[i][j] = 'X'

        # 将T标记为O
        for i in range(len(board)):
            for j in range(len(board[0])):
                if board[i][j] == 'T':
                    board[i][j] = 'O'

