class Solution(object):
    def numberToWords(self, num):
        """
        :type num: int
        :rtype: str
        """
        if num == 0:
            return "Zero"
        words = []
        billion = num / 10**9
        num %= 10**9
        million = num / 10**6
        num %= 10**6
        thousand = num / 10**3
        num %= 10**3
        rest = num
        if billion > 0:
            words.append(self.helper(billion))
            words.append("Billion")
        if million > 0:
            words.append(self.helper(million))
            words.append("Million")
        if thousand > 0:
            words.append(self.helper(thousand))
            words.append("Thousand")
        if rest > 0:
            words.append(self.helper(rest))
        return ' '.join(words)

    def helper(self, num):
        if num == 0:
            return ""
        elif num < 10:
            return self.ones(num)
        elif num < 20:
            return self.teens(num)
        else:
            return self.tens(num) + " " + self.ones(num % 10)

