class Solution(object):
    def findRedundantDirectedConnection(self, edges):
        n = len(edges)
        parent, root, idx = [None]*n, None, None
        for i, edge in enumerate(edges):
            if edge[1] == 0:
                root = i
            else:
                parent[edge[1] - 1] = i

        for i, edge in enumerate(edges):
            if edge[1] == 0:
                continue

            x, y = edge[0], edge[1]
            if self.find(parent, y) != -1:
                idx = i
                continue
            self.parent[y - 1] = x

        if idx is None:
            return edges[root]
        else:
            return edges[idx]

    def find(self, parent, y):
        while parent[y - 1] != -1:
            y = parent[y - 1]
        return y

