class Solution:
    def permuteUnique(self, nums):
        def backtrack(nums, path, res):
            if len(nums) == 0:
                res.append(path)
            for i in range(len(nums)):
                if i > 0 and nums[i] == nums[i - 1]:
                    continue
                backtrack(nums[:i] + nums[i + 1:], path + [nums[i]], res)

        res = []
        nums.sort()
        backtrack(nums, [], res)
        return res

