class Solution:
    def splitArray(self, nums, k):
        prefix = [0] * (len(nums) + 1)
        for i in range(len(nums)):
            prefix[i+1] = prefix[i] + nums[i]

        def check(m):
            cnt = 0
            for i in range(1, len(nums)+1):
                if prefix[i] - m < prefix[i-1]:
                    return False
                if prefix[i] - m == prefix[i-1]:
                    cnt += 1
                    if cnt == k:
                        return True
            return False

        l, r = max(nums), prefix[-1]
        while l < r:
            mid = (l + r) // 2
            if check(mid):
                r = mid
            else:
                l = mid + 1
        return l

