from typing import List

class FenwickTree:
    def __init__(self, n):
        self.size = n
        self.tree = [0] * (n + 1)

    def update(self, i, delta=1):
        while i <= self.size:
            self.tree[i] += delta
            i += i & -i

    def query(self, i):
        s = 0
        while i > 0:
            s += self.tree[i]
            i -= i & -i
        return s

    def range_query(self, i, j):
        return self.query(j) - self.query(i - 1)

def reversePairs(nums):
    n = len(nums)
    nums = [0] + nums + [0]
    nums.sort()
    ft = FenwickTree(20005)
    ans = 0
    for i, num in enumerate(nums):
        ans += ft.range_query(num//2 + 1, 20005)
        ft.update(num)
    return ans

