from collections import Counter
class Solution:
    def minStickersToSpellWord(self, stickers, target):
        """
        :type stickers: List[str]
        :type target: str
        :rtype: int
        """
        stickers_counts = [Counter(sticker) for sticker in stickers]
        memo = {tuple(sorted(target)): 0 for target in target}
        def dp(target):
            if tuple(sorted(target)) in memo:
                return memo[tuple(sorted(target))]
            res = float('inf')
            for i, sticker in enumerate(stickers):
                if stickers_counts[i][target[0]] > 0:
                    stickers_counts[i][target[0]] -= 1
                    res = min(res, dp("".join(ch for ch in target if ch != target[0])) + 1)
                    stickers_counts[i][target[0]] += 1
            memo[tuple(sorted(target))] = res
            return res
        return dp(target) if dp(target) != float('inf') else -1

