class Solution(object):
    def findMedianSortedArrays(self, nums1, nums2):
        """
        :type nums1: List[int]
        :type nums2: List[int]
        :rtype: float
        """
        total_length = len(nums1) + len(nums2)
        if total_length % 2 == 1:
            return self.getKth(nums1, nums2, total_length // 2)
        else:
            return (self.getKth(nums1, nums2, total_length // 2 - 1) +
                    self.getKth(nums1, nums2, total_length // 2)) / 2.0

    def getKth(self, nums1, nums2, k):
        if len(nums1) == 0:
            return nums2[k]
        if k == 0:
            return min(nums1[0], nums2[0])
        if len(nums1) == 1:
            if k == 1:
                return max(nums1[0], nums2[0])
            else:
                return nums2[k-1]
        if len(nums2) == 1:
            if k == 1:
                return max(nums1[0], nums2[0])
            else:
                return nums1[k-1]
        if k == 1:
            return max(nums1[0], nums2[0])
        if nums1[0] > nums2[0]:
            return self.getKth(nums1[1:], nums2, k-1)
        else:
            return self.getKth(nums1, nums2[1:], k-1)

