class Solution(object):
    def isScramble(self, s1, s2):
        """
        :type s1: str
        :type s2: str
        :rtype: bool
        """
        # DP table with dimensions (len(s1)+1, len(s2)+1, len(s1)+1) initialized to False
        dp = [[[[False] * (len(s1) + 1) for _ in range(len(s2) + 1)] for _ in range(len(s1) + 1)] for _ in range(2)]

        # Base cases: if both strings are empty, they are scrambles
        for l1 in range(len(s1) + 1):
            for l2 in range(len(s2) + 1):
                dp[l1 % 2][l1][l2] = dp[l1][l2 % 2][l2] = True

        # Check the rest of the table
        for l1 in range(1, len(s1) + 1):
            for l2 in range(1, len(s2) + 1):
                for l3 in range(1, min(l1, l2) + 1):
                    if l3 > 1 and s1[l1 - 1] == s2[l2 - 1] and s1[l1 - 1] == s2[l2 - 2]:
                        dp[l1 % 2][l2][l3] = dp[l1 - 1][l2 - 1][l3 - 1] and dp[l1 - 1][l2][l3] or \
                                               dp[l1 - 1][l2][l3] and dp[l1][l2 - 1][l3 - 1] or \
                                               dp[l1][l2][l3 - 1] and dp[l1 - 1][l2 - 2][l3]

        return dp[len(s1)][len(s2)][len(s1)]

