class Solution(object):
    def simplifyPath(self, path):
        """
        :type path: str
        :rtype: str
        """
        stack = []
        for part in path.split("/"):
            if part == "..":
                # Go up one level
                if stack:
                    stack.pop()
            elif part == "." or not part:
                # Stay on the same level or go down one level
                continue
            else:
                # Go down one level
                stack.append(part)

        return "/" + "/".join(stack)

