            node['#'] = word
        self.res = []
        self.board = board
        self.dx = [-1, 0, 1, 0]
        self.dy = [0, 1, 0, -1]
        self.visited = [[False]*len(board[0]) for _ in range(len(board))]
        for i in range(len(board)):
            for j in range(len(board[0])):
                self.dfs(trie, i, j, [])
        return self.res

    def dfs(self, node, i, j, path):
        if '#' in node:
            self.res.append(node['#'])
        self.visited[i][j] = True
        for k in range(4):
            x, y = i + self.dx[k], j + self.dy[k]
            if 0 <= x < len(self.board) and 0 <= y < len(self.board[0]) and self.board[x][y] in node and not self.visited[x][y]:
                self.dfs(node[self.board[x][y]], x, y, path + [self.board[x][y]])
        self.visited[i][j] = False

