        """
        :type pattern: str
        :type s: str
        :rtype: bool
        """
        words = s.split()
        if len(words) != len(pattern):
            return False

        dic = {}
        for i, char in enumerate(pattern):
            if char not in dic:
                if words[i] in dic.values():
                    return False
                dic[char] = words[i]
            elif dic[char] != words[i]:
                return False

        return True

