class Solution(object):
    def solveNQueens(self, n):
        """
        :type n: int
        :rtype: List[List[str]]
        """
        def is_valid(board, row, col):
            # Check this row on left side
            for i in range(col):
                if board[row][i] == 'Q':
                    return False

            # Check upper diagonal on left side
            for i, j in enumerate(range(row, -1, -1)):
                if board[j][i] == 'Q':
                    return False

            # Check lower diagonal on left side
            for i, j in enumerate(range(row, len(board))):
                if board[j][i] == 'Q':
                    return False

            return True

        def solve(board, row):
            if row == n:
                result.append(board)
                return 

            for col in range(n):
                if is_valid(board, row, col):
                    board[row][col] = 'Q'
                    solve(board, row + 1)
                    board[row][col] = '.'

        result = []
        board = [['.' for _ in range(n)] for _ in range(n)]
        solve(board, 0)
        return result

